$conf = "worker_processes 1;`nevents { worker_connections 1024; }`nhttp {`n    include       mime.types;`n    default_type  application/octet-stream;`n    sendfile on;`n    keepalive_timeout 65;`n    server {`n        listen 80;`n        server_name builddatanow.com www.builddatanow.com _;`n        location /.well-known/acme-challenge/ {`n            root C:/nginx/html;`n        }`n        location / {`n            proxy_pass         http://127.0.0.1:5000;`n            proxy_http_version 1.1;`n            proxy_set_header   Host              `$host;`n            proxy_set_header   X-Real-IP         `$remote_addr;`n            proxy_set_header   X-Forwarded-For   `$proxy_add_x_forwarded_for;`n        }`n    }`n}`n"
[System.IO.File]::WriteAllText("C:\nginx\conf\nginx.conf", $conf, [System.Text.Encoding]::ASCII)
Write-Host "Config written (ASCII)"
